// Match requested sections to library entries
const request = $('Narrative Request').first().json.body;
const requestedSections = request.sections || [];
const grantContext = request.grantContext || {};

const allNarratives = $('Get Narrative Library').all().map(i => i.json);

// Find matching narratives for each requested section
const matched = [];
const missing = [];

for (const sectionId of requestedSections) {
  const found = allNarratives.find(n => n.section_id === sectionId);
  if (found) {
    matched.push({
      section_id: found.section_id,
      section_name: found.section_name,
      base_content: found.base_content,
      word_limit: parseInt(found.word_limit) || 200,
      grantContext: grantContext
    });
  } else {
    missing.push(sectionId);
  }
}

// If no sections requested, return all
if (requestedSections.length === 0) {
  for (const n of allNarratives) {
    matched.push({
      section_id: n.section_id,
      section_name: n.section_name,
      base_content: n.base_content,
      word_limit: parseInt(n.word_limit) || 200,
      grantContext: grantContext
    });
  }
}

// Return as items for processing
return matched.map(m => ({ json: m }));

