const planeResponse = $('Get Narrative Library3').first().json;
  const requestedSections = $('Narrative Request1').first().json.body.sections;
  const grantContext = $('Narrative Request1').first().json.body.grantContext;

  // Parse all [Narrative] issues from Plane
  const allNarratives = [];
  const issues = planeResponse.results || [];

  for (const issue of issues) {
    const name = issue.name || '';
    const match = name.match(/^\[Narrative\]\s*(\w+)\s*-\s*(.+)$/i);

    if (match) {
      const sectionId = match[1].toLowerCase();
      const sectionName = match[2].trim();

      const desc = issue.description_html || '';
      let baseContent = '';
      let wordLimit = 250;

      const contentMatch = desc.match(/<p><strong>Base Content:<\/strong><\/p>([\s\S]*?)(?:<p><strong>Word Limit:|$)/i);
      if (contentMatch) {
        baseContent = contentMatch[1].replace(/<[^>]+>/g,'').replace(/\s+/g,'').trim();
      }

      const limitMatch = desc.match(/Word Limit:<\/strong>\s*(\d+)/i);
      if (limitMatch) {
        wordLimit = parseInt(limitMatch[1], 10);
      }

      allNarratives.push({
        section_id: sectionId,
        section_name: sectionName,
        base_content: baseContent,
        word_limit: wordLimit
      });
    }
  }

  // Match requested sections
  const matched = [];
  const missing = [];

  for (const sectionId of requestedSections) {
    const found = allNarratives.find(n => n.section_id === sectionId.toLowerCase());
    if (found) {
      matched.push({
        section_id: found.section_id,
        section_name: found.section_name,
        base_content: found.base_content,
        word_limit: found.word_limit,
        grantContext: grantContext,
        is_fallback: false
      });
    } else {
      missing.push(sectionId);
    }
  }

  // GRACEFUL FALLBACK: Return valid items the workflow can process
  if (matched.length === 0) {
    // Return a fallback item with the same structure so workflow continues
    const availableIds = allNarratives.map(n => n.section_id).sort();

    return [{
      json: {
        section_id: 'error_no_match',
        section_name: 'Section Not Found',
        base_content: `The requested sections (${requestedSections.join(', ')}) were not found in the
  narrative library. Available sections: ${availableIds.join(', ')}`,
        word_limit: 500,
        grantContext: grantContext,
        is_fallback: true,
        missing_sections: requestedSections,
        available_sections: availableIds
      }
    }];
  }

  // Return matched sections with any missing ones noted
  return matched.map(m => ({
    json: {
      ...m,
      missing_sections: missing.length > 0 ? missing : undefined
    }
  }));

