// Extract grant context from webhook body + Supabase grant data
const raw = $('Narrative Request').first().json;
const body = raw.body || {};
const payload = body.$json || body;

const grant_id = payload.grantId || payload.grant_id;
const org_id = payload.org_id;

if (!grant_id || !org_id) {
  return [{
    json: {
      error: true,
      message: `Missing required fields. grant_id: ${grant_id}, org_id: ${org_id}`,
    }
  }];
}

// Get grant data fetched from Supabase
const grantRows = $('Get Grant').first().json;
const grant = Array.isArray(grantRows) ? grantRows[0] : grantRows;

return [{
  json: {
    grant_id,
    org_id,
    grant_title: grant.title || grant.name || 'Not specified',
    grant_description: grant.description || grant.focus_areas || 'Not specified',
    funder_name: grant.funder_name || grant.funder || 'Not specified',
    deadline: grant.deadline || 'Not specified',
    amount: grant.amount || grant.award_amount || 'Not specified',
  }
}];

// Filter narrative documents for relevance to the grant, then pair with grant context
const documents = $('Get Narratives').all().map(item => item.json);
const gc = $('Extract Grant Context').first().json;

if (!documents || documents.length === 0 || !documents[0].id) {
  return [{
    json: {
      error: true,
      message: 'No narrative documents found for this org',
    }
  }];
}

// Build a searchable string from grant context for relevance matching
const grantText = [
  gc.grant_title,
  gc.grant_description,
  gc.funder_name,
].join(' ').toLowerCase();

// Keywords that map narrative categories/content to grant topics
const relevanceKeywords = {
  mission: ['mission', 'organization', 'nonprofit', 'community', 'overview', 'about'],
  impact: ['impact', 'outcomes', 'results', 'data', 'metrics', 'evaluation', 'measure'],
  methods: ['methods', 'approach', 'strategy', 'program', 'activities', 'services', 'intervention'],
  evaluation: ['evaluation', 'assessment', 'measure', 'outcomes', 'data', 'metrics'],
  youth: ['youth', 'foster', 'children', 'young', 'adolescent', 'teen', 'aging out'],
  seniors: ['senior', 'aging', 'elderly', 'older adults', 'long-term care', 'alzheimer', 'dementia'],
  equity: ['equity', 'racial', 'diversity', 'inclusion', 'african american', 'disparit'],
  workforce: ['workforce', 'employment', 'job', 'career', 'professional', 'work'],
  mental_health: ['mental health', 'trauma', 'healing', 'wellness', 'behavioral'],
  community: ['community', 'volunteer', 'partner', 'collaboration', 'local'],
};

// Score each document for relevance
const scored = documents.map(n => {
  const docText = [
    n.title || n.name || '',
    n.subcategory || '',
    n.extracted_text || '',
    (n.tags || []).join(' '),
  ].join(' ').toLowerCase();

  let score = 0;

  // Always include mission/overview documents (score boost)
  const docTitle = (n.title || n.name || '').toLowerCase();
  const docSubcat = (n.subcategory || '').toLowerCase();
  if (docSubcat === 'mission' || docTitle.includes('mission')) {
    score += 3;
  }

  // Check if document keywords appear in grant text
  for (const [category, keywords] of Object.entries(relevanceKeywords)) {
    const docMatchesCategory = keywords.some(kw => docText.includes(kw));
    const grantMatchesCategory = keywords.some(kw => grantText.includes(kw));
    if (docMatchesCategory && grantMatchesCategory) {
      score += 2;
    }
  }

  // Direct word overlap between document title and grant text
  const titleWords = docTitle.split(/\s+/);
  for (const word of titleWords) {
    if (word.length > 3 && grantText.includes(word)) {
      score += 1;
    }
  }

  return { document: n, score };
});

// Filter: keep documents with score > 0, sorted by relevance
let relevant = scored.filter(s => s.score > 0).sort((a, b) => b.score - a.score);

// Fallback: if nothing matched, use mission + methods + impact documents
if (relevant.length === 0) {
  const fallbackKeywords = ['mission', 'method', 'impact'];
  relevant = scored.filter(s => {
    const text = (s.document.title || s.document.name || s.document.subcategory || '').toLowerCase();
    return fallbackKeywords.some(kw => text.includes(kw));
  });
}

// Still nothing? Use all documents
if (relevant.length === 0) {
  relevant = scored;
}

return relevant.map(s => ({
  json: {
    narrative_id: s.document.id,
    section_id: s.document.subcategory || 'general',
    section_name: s.document.title || s.document.name,
    base_content: s.document.extracted_text,
    word_limit: s.document.metadata?.word_count || 250,
    relevance_score: s.score,
    grantContext: gc,
  }
}));

